/* GENERATED by gennet.py from pip_resolver.net.json — DO NOT EDIT BY HAND.
 * The PIP_RESOLVER device: samples the NIC seam's SEAM_SYMBOL, indexes a static
 * pip-config table by the symbol address (symbol*8 bytes = the symbol-th slot;
 * power-of-two mask, no %), and publishes the resolved pip value on
 * PIP_RESOLUTION_REG. A netlist of cells over addressed registers. No branch in
 * the data path; no native add/sub/mul; the config table is read-only in the tick. */
#ifndef PIP_RESOLVER_GEN_H
#define PIP_RESOLVER_GEN_H
#include "cells.h"
#include "nic_gen.h"       /* the NIC's CANONICAL output window (generated from
                            * ../nic/nic.net.json by the NIC's gennet — single
                            * source). The PIP_RESOLVER SAMPLES the SEAM_SYMBOL /
                            * SEAM_VALID lanes; no private copy. */

#define PIP_REG_COUNT 22u
#define PIP_WINDOW_BASE 0x2000000u
#define PIP_TABLE_DEPTH 16u
#define PIP_TABLE_MASK (PIP_TABLE_DEPTH - 1u)

#define PIP_PIP_POWER 0u
#define PIP_PIP_RUN_UNTIL 1u
#define PIP_PIP_CFG_TABLE_0 2u
#define PIP_PIP_CFG_TABLE_1 3u
#define PIP_PIP_CFG_TABLE_2 4u
#define PIP_PIP_CFG_TABLE_3 5u
#define PIP_PIP_CFG_TABLE_4 6u
#define PIP_PIP_CFG_TABLE_5 7u
#define PIP_PIP_CFG_TABLE_6 8u
#define PIP_PIP_CFG_TABLE_7 9u
#define PIP_PIP_CFG_TABLE_8 10u
#define PIP_PIP_CFG_TABLE_9 11u
#define PIP_PIP_CFG_TABLE_10 12u
#define PIP_PIP_CFG_TABLE_11 13u
#define PIP_PIP_CFG_TABLE_12 14u
#define PIP_PIP_CFG_TABLE_13 15u
#define PIP_PIP_CFG_TABLE_14 16u
#define PIP_PIP_CFG_TABLE_15 17u
#define PIP_PIP_TICKS 18u
#define PIP_PIP_RESOLUTION_REG 19u
#define PIP_PIP_SYMBOL 20u
#define PIP_PIP_VALID 21u


/* pip_cmp_lt: gate-netlist comparator (a < b), carry chain over cell_fa. The
 * bounded self-run uses it on a configured tick budget (config, not external
 * stepping). Device-local name (avoid colliding with an included cmp_lt). */
static inline word_t pip_cmp_lt(word_t a, word_t b) {
    word_t carry = 1ULL;
    word_t i = 0ULL;
    for (i = 0ULL; i < 64ULL; i = i + 1ULL) {
        const word_t aa = (a >> i) & 1ULL;
        const word_t nb = (cell_not(b) >> i) & 1ULL;
        const word_t fa = cell_fa(aa, nb, carry);
        carry           = (fa >> 1) & 1ULL;
    }
    return (carry & 1ULL) ^ 1ULL;
}


static inline void pip_resolver_init(word_t *r) {
    word_t i = 0ULL;
    for (i = 0ULL; i < PIP_REG_COUNT; i = i + 1ULL) { r[i] = 0ULL; }
}

/* pip_resolver_tick: one MAC clock edge. READ the NIC seam (SEAM_SYMBOL,
 * SEAM_VALID) + the static table slot at idx = symbol & MASK, COMPUTE the
 * resolved pip value (branchless eqmask-gate-OR slot select), WRITE the
 * output lanes + status. The config table is READ-only here. Write-only
 * WRITE phase. */
static inline void pip_resolver_tick(word_t *r, const word_t *nic) {
    /* READ phase — pre-read every operand from its register. */
    const word_t power  = r[PIP_PIP_POWER] & 1ULL;
    const word_t symbol = nic[NIC_SEAM_SYMBOL];
    const word_t valid  = nic[NIC_SEAM_VALID] & 1ULL;

    /* table index = SEAM_SYMBOL & (depth-1) — a branchless power-of-two
     * mask cell (depth is a power of two; the symbol*8 byte address maps
     * to word slot = symbol, reduced to the table range; no %, no if). */
    const word_t idx = cell_and(symbol, PIP_TABLE_MASK);
    /* read the addressed table slot (branchless select: eqmask(idx,i)
     * gates exactly one config slot through; OR-reduce the rest as 0). */
    word_t res = 0ULL;
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_0], cell_eqmask(idx, 0ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_1], cell_eqmask(idx, 1ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_2], cell_eqmask(idx, 2ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_3], cell_eqmask(idx, 3ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_4], cell_eqmask(idx, 4ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_5], cell_eqmask(idx, 5ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_6], cell_eqmask(idx, 6ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_7], cell_eqmask(idx, 7ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_8], cell_eqmask(idx, 8ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_9], cell_eqmask(idx, 9ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_10], cell_eqmask(idx, 10ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_11], cell_eqmask(idx, 11ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_12], cell_eqmask(idx, 12ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_13], cell_eqmask(idx, 13ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_14], cell_eqmask(idx, 14ULL)));
    res = cell_or(res, cell_gate(r[PIP_PIP_CFG_TABLE_15], cell_eqmask(idx, 15ULL)));

    /* COMPUTE phase — the latch enable: only a valid sampled symbol
     * updates the resolved output. */
    const word_t en = valid;

    /* output flops: latch the resolved pip value + the symbol on en=valid
     * (gated dff); PIP_VALID latches SEAM_VALID while powered. */
    const word_t out_pip_resolution_reg = cell_dff(r[PIP_PIP_RESOLUTION_REG], res, en);
    const word_t out_pip_symbol = cell_dff(r[PIP_PIP_SYMBOL], symbol, en);
    const word_t st_pip_valid = cell_dff(r[PIP_PIP_VALID], valid, power);

    /* WRITE phase — commit every dff (registered hop). Write-only. */
    r[PIP_PIP_RESOLUTION_REG] = out_pip_resolution_reg;
    r[PIP_PIP_SYMBOL] = out_pip_symbol;
    r[PIP_PIP_VALID] = st_pip_valid;
}

/* pip_resolver_run: the canonical clock primitive. The device self-runs
 * on the mac edge while powered, bounded by a configured tick budget
 * (config, not external stepping). The starter powers it on, configures
 * the static table, and steps away. */
static inline void pip_resolver_run(word_t *r, const word_t *nic) {
    while ((r[PIP_PIP_POWER] & 1ULL)
           && pip_cmp_lt(r[PIP_PIP_TICKS], r[PIP_PIP_RUN_UNTIL])) {
        pip_resolver_tick(r, nic);
        r[PIP_PIP_TICKS] = cell_addsub(r[PIP_PIP_TICKS], 1ULL, 0ULL);
    }
}

#endif /* PIP_RESOLVER_GEN_H */
